#include <stdio.h>

/* Object-like macros */
#define PI 3.14159
#define MAX_BUF 256
#define DEBUG 1

/* Function-like macros (with proper parenthesization) */
#define SQUARE(x)   ((x) * (x))
#define MAX(a, b)   ((a) > (b) ? (a) : (b))
#define MIN(a, b)   ((a) < (b) ? (a) : (b))
#define ABS(x)      ((x) >= 0 ? (x) : -(x))

/* Multi-line macro */
#define SWAP(a, b, type) do { \
    type _tmp = (a);           \
    (a) = (b);                 \
    (b) = _tmp;                \
} while (0)

int main(void) {
    printf("PI = %f\n", PI);  /* 3.141590 */
    printf("SQUARE(5) = %d\n", SQUARE(5)); /* 25 */
    printf("MAX(3, 7) = %d\n", MAX(3, 7)); /* 7 */

    /* Works with any type */
    printf("MAX(3.5, 2.1) = %f\n", MAX(3.5, 2.1)); /* 3.5 */

    /* do-while(0) pattern for multi-statement macros */
    int x = 10, y = 20;
    SWAP(x, y, int);
    printf("x=%d y=%d\n", x, y); /* x=20 y=10 */

    #if DEBUG
        printf("Debug mode is on\n");
    #endif

    return 0;
}

