#include <stdio.h>

/* BAD: no parentheses */
#define BAD_SQUARE(x) x * x
/* GOOD: proper parentheses */
#define GOOD_SQUARE(x) ((x) * (x))

/* BAD: double evaluation */
#define BAD_MAX(a, b) ((a) > (b) ? (a) : (b))

/* GOOD: inline function avoids double evaluation */
static inline int safe_max(int a, int b) {
    return (a > b) ? a : b;
}

/* GOOD: multi-statement macro with do-while(0) */
#define SAFE_SWAP(a, b, type) do { \
    type _tmp = (a);                \
    (a) = (b);                      \
    (b) = _tmp;                     \
} while (0)

int main(void) {
    /* Precedence bug */
    printf("BAD:  SQUARE(2+3) = %d\n", BAD_SQUARE(2+3));  /* 11 (wrong!) */
    printf("GOOD: SQUARE(2+3) = %d\n", GOOD_SQUARE(2+3)); /* 25 */

    /* Double evaluation bug */
    int i = 5, j = 3;
    int m = BAD_MAX(i++, j++);
    printf("BAD_MAX: m=%d i=%d j=%d\n", m, i, j);
    /* i incremented TWICE: i=7, not 6 */

    /* Safe version */
    i = 5; j = 3;
    m = safe_max(i++, j++);
    printf("safe_max: m=%d i=%d j=%d\n", m, i, j);
    /* i=6, j=4 (each incremented once) */

    /* do-while(0) works in if-else */
    int x = 10, y = 20;
    if (1)
        SAFE_SWAP(x, y, int);
    else
        printf("no swap\n");
    printf("x=%d y=%d\n", x, y); /* x=20 y=10 */

    return 0;
}

