/* Stringification: # turns argument into string */
#define TO_STRING(x) #x
#define PRINT_VAR(var) printf(#var " = %d\n", (var))

/* Token pasting: ## concatenates tokens */
#define MAKE_VAR(prefix, num) prefix##num
#define MAKE_FUNC(name) name##_create

/* Practical: debug print */
#define DEBUG_INT(x) printf("%s = %d\n", #x, (x))
#define DEBUG_STR(x) printf("%s = \"%s\"\n", #x, (x))

/* Indirect stringification (for expanding macros) */
#define STRINGIFY(x) #x
#define EXPAND_STRINGIFY(x) STRINGIFY(x)
#define VERSION 42

int MAKE_FUNC(widget)(int n) {
    printf("Creating widget %d\n", n);
    return n;
}

int main(void) {
    /* Stringification */
    printf("%s\n", TO_STRING(hello world)); /* "hello world" */

    int x = 42;
    PRINT_VAR(x);   /* x = 42 */
    PRINT_VAR(x*2); /* x*2 = 84 */

    /* Token pasting */
    int MAKE_VAR(count, 1) = 10;  /* creates count1 */
    int MAKE_VAR(count, 2) = 20;  /* creates count2 */
    printf("count1=%d count2=%d\n", count1, count2);

    /* Function name generation */
    widget_create(5); /* Creating widget 5 */

    /* Debug macros */
    DEBUG_INT(x + 10);  /* x + 10 = 52 */
    DEBUG_STR("hello"); /* "hello" = "hello" */

    /* Indirect stringify expands macros first */
    printf("VERSION = %s\n", EXPAND_STRINGIFY(VERSION)); /* 42 */
    printf("VERSION = %s\n", STRINGIFY(VERSION));         /* VERSION */

    return 0;
}

